// 題庫顯示順序（分類內依此排；Agent 走 arc：規劃→工具→JSON→記憶→量化→成本）
export const IV_ORDER = [
  // 原理：由淺到深，對齊課程 Tokenizer → Embedding → Transformer(attention)
  "tokenizer-why", "embedding-meaning", "attention-compute", "multi-head", "positional-encoding", "transformer-vs-rnn", "what-model-stores", "emergence",
  // 訓練
  "rlhf-why", "dpo-pipeline", "finetune-vs-rag", "lora", "catastrophic-forgetting", "data-quality", "why-not-pretrain", "scaling-law",
  // 推論：先「訓練 vs 推論」建立概念，再談限制
  "train-vs-infer", "context-window", "faster-inference", "quantization", "temperature",
  // Prompting：先學技巧（few-shot／CoT）再學評估
  "prompt-craft", "few-shot", "sycophancy", "honest-feedback", "manage-context", "outline-workflow", "cot-prompting", "prompt-eval", "prompt-vs-tune-vs-rag", "reasoning-models", "test-time-compute", "cot-limits",
  // 檢索（RAG）
  "vector-search", "rag-documents", "chunking", "rag-retrieval", "rag-why-wrong", "rag-vs-longcontext",
  // Agent arc：概念→規劃→工具→JSON→記憶→量化→成本
  "agent-vs-workflow", "agent-planning", "loop-control", "self-verify", "agent-tools", "json-output", "agent-memory", "agent-eval", "agent-cost",
  // 生成／多模態：先生圖（擴散）成一組，再進多模態
  "diffusion-how", "diffusion-not-collage", "genimg-errors", "diffusion-vs-gan", "multimodal-key", "vlm-see",
  // 素養／風險：可靠性 → 安全 → 能力邊界
  "hallucination", "bias", "trust-answer", "prompt-injection", "jailbreak", "guardrails", "data-leakage", "ai-limits", "can-llm-reason",
  // 系統設計
  "design-doc-qa", "design-support-bot", "realtime-assistant", "design-build-vs-buy", "design-data-pipeline", "design-latency-scale", "design-cost", "design-eval-improve", "monitoring",
  // 評估與決策
  "eval-benchmark", "eval-llm-judge", "eval-set", "eval-offline-online", "eval-regression",
];

/** 依分類 key 取該類題目 id 陣列（依 IV_ORDER 排序） */
export function ivByCat(catKey) {
  return IV_ORDER.filter((id) => INTERVIEWS[id]?.cat === catKey);
}

/** 分類名稱（在地化，缺就回中文） */
export function catNameOf(key, locale = 'zh') {
  return (locale !== 'zh' && CAT_TR[locale]?.[key]) || IV_CATS.find((c) => c.key === key)?.t || '';
}

/** 側邊短標籤（在地化） */
export function ivLabel(id, locale = 'zh') {
  return (locale !== 'zh' && INT_TR[locale]?.[id]?.label) || INTERVIEWS[id]?.label || '';
}

/** 取一題的在地化內容（欄位逐一 fallback 回中文；points 的 icon 沿用 base） */
export function ivOf(id, locale = 'zh') {
  const base = INTERVIEWS[id];
  if (!base) return base;
  const tr = locale !== 'zh' ? INT_TR[locale]?.[id] : null;
  if (!tr) return base;
  return {
    ...base,
    label: tr.label ?? base.label,
    q: tr.q ?? base.q,
    trap: tr.trap ?? base.trap,
    points: base.points.map((p, i) => ({
      icon: p.icon,
      title: tr.points?.[i]?.title ?? p.title,
      desc: tr.points?.[i]?.desc ?? p.desc,
    })),
    core: base.core.map((c, i) => ({ h: tr.core?.[i]?.h ?? c.h, d: tr.core?.[i]?.d ?? c.d })),
    plus: tr.plus ?? base.plus,
    traps: tr.traps ?? base.traps,
  };
}
